func HasLionResourceTypesWith(preds ...predicate.ResourceTypes) predicate.Actions {
	return predicate.Actions(func(s *sql.Selector) {
		step := newLionResourceTypesStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Actions) predicate.Actions {
	return predicate.Actions(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Actions) predicate.Actions {
	return predicate.Actions(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Actions) predicate.Actions {
	return predicate.Actions(sql.NotPredicates(p))
}
